package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlin.test.*

/**
 * Tests for bug fixes related to ISO 8601 parsing consistency issues.
 * 
 * See https://gist.github.com/ilma4/a5ad5b5c284969e24f4e2149a2f8b273 for the original bug report.
 */
class BugfixTest {

    /**
     * Test that LocalDate.parse() and LocalDate.Formats.ISO.parse() produce the same results,
     * including for dates with many leading zeroes like "+00000000000002022-07-16".
     * 
     * Previously, LocalDate.parse() on JVM/JS delegated to Java's parsing, which doesn't support
     * too many leading zeroes, while Formats.ISO.parse() used Kotlin's own parsing which does.
     */
    @Test
    fun localDateParseConsistency() {
        val testCases = listOf(
            "2022-07-16",
            "+2022-07-16",
            "+02022-07-16",
            "+002022-07-16",
            "+0002022-07-16",
            "+00002022-07-16",
            "+000002022-07-16",
            "+0000002022-07-16",
            "+00000002022-07-16",
            "+000000002022-07-16",
            "+0000000002022-07-16",
            "+00000000002022-07-16",
            "+000000000002022-07-16",
            "+00000000000002022-07-16",
        )

        for (input in testCases) {
            val expected = LocalDate(2022, 7, 16)
            val parsedDefault = LocalDate.parse(input)
            val parsedFormat = LocalDate.Formats.ISO.parse(input)

            assertEquals(expected, parsedDefault, "LocalDate.parse('$input') should equal expected")
            assertEquals(expected, parsedFormat, "LocalDate.Formats.ISO.parse('$input') should equal expected")
            assertEquals(parsedDefault, parsedFormat, "LocalDate.parse('$input') should equal Formats.ISO.parse('$input')")
        }
    }

    /**
     * Test that LocalDateTime.parse() and LocalDateTime.Formats.ISO.parse() produce the same results,
     * including for dates with many leading zeroes.
     */
    @Test
    fun localDateTimeParseConsistency() {
        val testCases = listOf(
            "2022-07-16T12:30:45",
            "+2022-07-16T12:30:45",
            "+02022-07-16T12:30:45",
            "+002022-07-16T12:30:45",
            "+0002022-07-16T12:30:45",
            "+00002022-07-16T12:30:45",
            "+000002022-07-16T12:30:45",
            "+0000002022-07-16T12:30:45",
            "+00000002022-07-16T12:30:45",
            "+000000002022-07-16T12:30:45",
            "+0000000002022-07-16T12:30:45",
            "+00000000002022-07-16T12:30:45",
            "+000000000002022-07-16T12:30:45",
            "+00000000000002022-07-16T12:30:45",
        )

        for (input in testCases) {
            val expected = LocalDateTime(2022, 7, 16, 12, 30, 45)
            val parsedDefault = LocalDateTime.parse(input)
            val parsedFormat = LocalDateTime.Formats.ISO.parse(input)

            assertEquals(expected, parsedDefault, "LocalDateTime.parse('$input') should equal expected")
            assertEquals(expected, parsedFormat, "LocalDateTime.Formats.ISO.parse('$input') should equal expected")
            assertEquals(parsedDefault, parsedFormat, "LocalDateTime.parse('$input') should equal Formats.ISO.parse('$input')")
        }
    }

    /**
     * Test that DateTimePeriod.parse("P") fails with an appropriate error.
     * According to ISO 8601, a period must have at least one component after "P".
     */
    @Test
    fun dateTimePeriodParseEmptyP() {
        // Just "P" without any components should fail
        assertFailsWith<DateTimeFormatException> { DateTimePeriod.parse("P") }

        // Just "+P" without any components should fail
        assertFailsWith<DateTimeFormatException> { DateTimePeriod.parse("+P") }

        // Just "-P" without any components should fail
        assertFailsWith<DateTimeFormatException> { DateTimePeriod.parse("-P") }
    }

    /**
     * Test that DatePeriod.parse("P") also fails appropriately.
     */
    @Test
    fun datePeriodParseEmptyP() {
        // Just "P" without any components should fail
        assertFailsWith<DateTimeFormatException> { DatePeriod.parse("P") }

        // Just "+P" without any components should fail
        assertFailsWith<DateTimeFormatException> { DatePeriod.parse("+P") }

        // Just "-P" without any components should fail
        assertFailsWith<DateTimeFormatException> { DatePeriod.parse("-P") }
    }

    /**
     * Test that "PT" (P followed by T but no time components) still fails appropriately.
     */
    @Test
    fun dateTimePeriodParsePTWithoutTimeComponents() {
        // "PT" without time components should fail
        assertFailsWith<DateTimeFormatException> { DateTimePeriod.parse("PT") }
    }

    /**
     * Test that valid period strings still parse correctly.
     */
    @Test
    fun dateTimePeriodParseValidStrings() {
        // These should all still work
        assertEquals(DateTimePeriod(days = 0), DateTimePeriod.parse("P0D"))
        assertEquals(DateTimePeriod(years = 1), DateTimePeriod.parse("P1Y"))
        assertEquals(DateTimePeriod(months = 1), DateTimePeriod.parse("P1M"))
        assertEquals(DateTimePeriod(days = 1), DateTimePeriod.parse("P1D"))
        assertEquals(DateTimePeriod(hours = 1), DateTimePeriod.parse("PT1H"))
        assertEquals(DateTimePeriod(minutes = 1), DateTimePeriod.parse("PT1M"))
        assertEquals(DateTimePeriod(seconds = 1), DateTimePeriod.parse("PT1S"))
        assertEquals(DateTimePeriod(years = 1, months = 2, days = 3, hours = 4, minutes = 5, seconds = 6), 
            DateTimePeriod.parse("P1Y2M3DT4H5M6S"))
    }
}
