        val testCases = listOf(
            "2022-07-16",
            "+2022-07-16",
            "+02022-07-16",
            "+002022-07-16",
            "+0002022-07-16",
            "+00002022-07-16",
            "+000002022-07-16",
            "+0000002022-07-16",
            "+00000002022-07-16",
